+package org.elasticsearch.bootstrap;
+
+import org.apache.lucene.util.Constants;
+import org.apache.lucene.util.LuceneTestCase;
+import org.elasticsearch.Version;
+import org.elasticsearch.common.settings.Settings;
+import org.elasticsearch.env.Environment;
+import org.elasticsearch.env.TestEnvironment;
+import org.elasticsearch.plugins.PluginTestUtil;
+import org.elasticsearch.plugins.Platforms;
+
+import java.io.IOException;
+import java.lang.reflect.Field;
+import java.nio.charset.StandardCharsets;
+import java.nio.file.Files;
+import java.nio.file.Path;
+import java.nio.file.attribute.PosixFileAttributeView;
+import java.nio.file.attribute.PosixFilePermission;
+import java.util.HashSet;
+import java.util.Set;
+
+import static org.hamcrest.Matchers.hasSize;
+
+public class SpawnerNoBootstrapFallbackControllerTests extends LuceneTestCase {
+
+    private static final String CONTROLLER_SOURCE = "#!/bin/bash\n"
+        + "\n"
+        + "echo I am alive\n"
+        + "\n"
+        + "read SOMETHING\n";
+
+    public void testDoesNotSpawnFallbackNativeControllerOnMac() throws Exception {
+        assumeFalse("This test does not work on Windows", Constants.WINDOWS);
+
+        final boolean originalMacOsX = Constants.MAC_OS_X;
+        final String originalPlatformName = Platforms.PLATFORM_NAME;
+        try {
+            setStaticField(Constants.class, "MAC_OS_X", true);
+            setStaticField(Platforms.class, "PLATFORM_NAME", "darwin-x86_64");
+
+            final Path esHome = createTempDir().resolve("esHome");
+            final Settings settings = Settings.builder().put(Environment.PATH_HOME_SETTING.getKey(), esHome.toString()).build();
+            final Environment environment = TestEnvironment.newEnvironment(settings);
+
+            Files.createDirectories(environment.modulesFile());
+
+            final Path module = environment.modulesFile().resolve("test_module");
+            Files.createDirectories(module);
+            PluginTestUtil.writePluginProperties(
+                module,
+                "description", "test_module",
+                "version", Version.CURRENT.toString(),
+                "elasticsearch.version", Version.CURRENT.toString(),
+                "name", "test_module",
+                "java.version", "1.8",
+                "classname", "TestModule",
+                "has.native.controller", "true");
+
+            createControllerProgram(module.resolve("platform").resolve("darwin-x86_64").resolve("bin").resolve("controller"));
+
+            try (Spawner spawner = new Spawner()) {
+                spawner.spawnNativeControllers(environment);
+                assertThat(spawner.getProcesses(), hasSize(0));
+            }
+        } finally {
+            setStaticField(Constants.class, "MAC_OS_X", originalMacOsX);
+            setStaticField(Platforms.class, "PLATFORM_NAME", originalPlatformName);
+        }
+    }
+
+    private void setStaticField(final Class<?> clazz, final String fieldName, final Object value) throws Exception {
+        final Field field = clazz.getDeclaredField(fieldName);
+        final Object unsafe = getUnsafe();
+        final Object base = unsafe.getClass().getMethod("staticFieldBase", Field.class).invoke(unsafe, field);
+        final long offset = (long) unsafe.getClass().getMethod("staticFieldOffset", Field.class).invoke(unsafe, field);
+        if (field.getType() == boolean.class) {
+            unsafe.getClass().getMethod("putBoolean", Object.class, long.class, boolean.class).invoke(unsafe, base, offset, (boolean) value);
+        } else {
+            unsafe.getClass().getMethod("putObject", Object.class, long.class, Object.class).invoke(unsafe, base, offset, value);
+        }
+    }
+
+    private Object getUnsafe() throws Exception {
+        final Class<?> unsafeClass = Class.forName("sun.misc.Unsafe");
+        final Field field = unsafeClass.getDeclaredField("theUnsafe");
+        field.setAccessible(true);
+        return field.get(null);
+    }
+
+    private void createControllerProgram(final Path outputFile) throws IOException {
+        final Path outputDir = outputFile.getParent();
+        Files.createDirectories(outputDir);
+        Files.write(outputFile, CONTROLLER_SOURCE.getBytes(StandardCharsets.UTF_8));
+        final PosixFileAttributeView view = Files.getFileAttributeView(outputFile, PosixFileAttributeView.class);
+        if (view != null) {
+            final Set<PosixFilePermission> perms = new HashSet<>();
+            perms.add(PosixFilePermission.OWNER_READ);
+            perms.add(PosixFilePermission.OWNER_WRITE);
+            perms.add(PosixFilePermission.OWNER_EXECUTE);
+            perms.add(PosixFilePermission.GROUP_READ);
+            perms.add(PosixFilePermission.GROUP_EXECUTE);
+            perms.add(PosixFilePermission.OTHERS_READ);
+            perms.add(PosixFilePermission.OTHERS_EXECUTE);
+            Files.setPosixFilePermissions(outputFile, perms);
+        }
+    }
+}
